// Profile.jsx - Light Theme with Perfect Layout
import React, { useState, useEffect } from 'react';
import './Profile.css';

// Advanced Hooks
const useAIMoodBackground = (userMood) => {
  const [background, setBackground] = useState('');
  
  useEffect(() => {
    const moodGradients = {
      calm: 'linear-gradient(135deg, #e3f2fd 0%, #bbdefb 50%, #90caf9 100%)',
      focused: 'linear-gradient(135deg, #f3e5f5 0%, #e1bee7 50%, #ce93d8 100%)',
      energetic: 'linear-gradient(135deg, #fff8e1 0%, #ffecb3 50%, #ffd54f 100%)',
      relaxed: 'linear-gradient(135deg, #e8f5e8 0%, #c8e6c9 50%, #a5d6a7 100%)',
      creative: 'linear-gradient(135deg, #fce4ec 0%, #f8bbd9 50%, #f48fb1 100%)'
    };
    
    setBackground(moodGradients[userMood] || moodGradients.calm);
  }, [userMood]);
  
  return background;
};

const useBiometricData = (userId) => {
  const [biometrics, setBiometrics] = useState({
    heartRate: 72,
    stressLevel: 35,
    focusScore: 78,
    sleepQuality: 85,
    moodStability: 90
  });
  
  useEffect(() => {
    const interval = setInterval(() => {
      setBiometrics(prev => ({
        heartRate: Math.max(60, Math.min(100, prev.heartRate + (Math.random() - 0.5) * 10)),
        stressLevel: Math.max(0, Math.min(100, prev.stressLevel + (Math.random() - 0.5) * 5)),
        focusScore: Math.max(0, Math.min(100, prev.focusScore + (Math.random() - 0.5) * 8)),
        sleepQuality: Math.max(0, Math.min(100, prev.sleepQuality + (Math.random() - 0.5) * 3)),
        moodStability: Math.max(0, Math.min(100, prev.moodStability + (Math.random() - 0.5) * 2))
      }));
    }, 3000);
    
    return () => clearInterval(interval);
  }, [userId]);
  
  return biometrics;
};

// Holographic Avatar Component (Light Theme)
const HolographicAvatar = ({ user, currentMood }) => {
  const [rotation, setRotation] = useState({ x: 0, y: 0 });
  
  const handleMouseMove = (e) => {
    const rect = e.currentTarget.getBoundingClientRect();
    const x = ((e.clientX - rect.left) / rect.width - 0.5) * 20;
    const y = ((e.clientY - rect.top) / rect.height - 0.5) * 20;
    setRotation({ x, y });
  };
  
  return (
    <div 
      className="holographic-avatar-container"
      onMouseMove={handleMouseMove}
      onMouseLeave={() => setRotation({ x: 0, y: 0 })}
    >
      <div 
        className="holographic-avatar"
        style={{
          transform: `rotateX(${rotation.y}deg) rotateY(${rotation.x}deg)`
        }}
      >
        <div className="avatar-core">
          <div className="avatar-initial">
            {user.username?.charAt(0).toUpperCase() || 'U'}
          </div>
        </div>
        <div className="hologram-ring ring-1"></div>
        <div className="hologram-ring ring-2"></div>
        <div className="mood-aura" data-mood={currentMood}></div>
      </div>
    </div>
  );
};

// Mini Mood Graph Component
const MiniMoodGraph = ({ data }) => {
  return (
    <div className="mini-mood-graph">
      <div className="graph-bars">
        {data.map((day, index) => (
          <div key={index} className="bar-container">
            <div 
              className="bar" 
              style={{ height: `${day.value}%` }}
              data-mood={day.mood}
            ></div>
            <span className="day-label">{day.date}</span>
          </div>
        ))}
      </div>
    </div>
  );
};

// Achievement Badges Component
const AchievementBadges = ({ achievements }) => {
  return (
    <div className="achievement-badges">
      {achievements.map((achievement, index) => (
        <div 
          key={achievement.id}
          className={`achievement-badge ${achievement.unlocked ? 'unlocked' : 'locked'}`}
          style={{ animationDelay: `${index * 0.1}s` }}
        >
          <div className="badge-icon">
            {achievement.unlocked ? achievement.icon : '🔒'}
          </div>
          <div className="badge-info">
            <span className="badge-name">{achievement.name}</span>
          </div>
        </div>
      ))}
    </div>
  );
};

// Progress Bar Component
const ProgressBar = ({ current, total, label, reward }) => {
  const percentage = (current / total) * 100;
  
  return (
    <div className="progress-card">
      <div className="progress-header">
        <span className="progress-label">{label}</span>
        <span className="progress-count">{current}/{total}</span>
      </div>
      <div className="progress-bar-container">
        <div 
          className="progress-bar-fill"
          style={{ width: `${percentage}%` }}
        ></div>
      </div>
      <div className="progress-reward">
        <span className="reward-text">Reward: {reward}</span>
      </div>
    </div>
  );
};

// Main Profile Component
function Profile({ user, onUpdateUser, onShowSettings, onLogout }) {
  const [currentMood, setCurrentMood] = useState('focused');
  const [activeTool, setActiveTool] = useState(null);
  
  // Advanced Hooks
  const background = useAIMoodBackground(currentMood);
  const biometrics = useBiometricData(user.id);
  
  // Mock data
  const moodData = [
    { date: 'Mon', value: 75, mood: 'Focused' },
    { date: 'Tue', value: 60, mood: 'Calm' },
    { date: 'Wed', value: 85, mood: 'Energetic' },
    { date: 'Thu', value: 45, mood: 'Tired' },
    { date: 'Fri', value: 80, mood: 'Creative' },
    { date: 'Sat', value: 90, mood: 'Inspired' },
    { date: 'Sun', value: 70, mood: 'Relaxed' }
  ];
  
  const achievements = [
    { id: 1, name: 'Early Bird', icon: '🌅', unlocked: true },
    { id: 2, name: 'Meditation Master', icon: '🧘', unlocked: true },
    { id: 3, name: 'Streak Star', icon: '🔥', unlocked: false },
    { id: 4, name: 'Sleep Guru', icon: '🌙', unlocked: true },
    { id: 5, name: 'Mood Master', icon: '😊', unlocked: false },
    { id: 6, name: 'Consistency King', icon: '👑', unlocked: true }
  ];

  const tools = {
    wellness: [
      { id: 'breathing', name: 'Breathing Exercises', icon: '🌬️', free: true },
      { id: 'games', name: 'Mindful Games', icon: '🎮', free: true },
      { id: 'meditation', name: 'Meditation', icon: '🧘', free: false },
      { id: 'sleep', name: 'Sleep Companion', icon: '🌙', free: false }
    ],
    growth: [
      { id: 'journal', name: 'Journal', icon: '📔', free: true },
      { id: 'report', name: 'Mood Reports', icon: '📊', free: true },
      { id: 'aiCoach', name: 'AI Coach', icon: '🤖', free: false }
    ],
    customization: [
      { id: 'shop', name: 'Shop', icon: '🛒', free: true },
      { id: 'themes', name: 'Themes & Avatars', icon: '🎨', free: true }
    ]
  };

  const handleToolClick = (tool) => {
    if (!tool.free && !user.is_premium) {
      // Show premium popup
      console.log('Premium feature:', tool.name);
      return;
    }
    setActiveTool(tool.id);
  };

  return (
    <div className="profile-container" style={{ background }}>
      <div className="profile-content">
        
        {/* Hero Section */}
        <section className="hero-section">
          <div className="hero-content">
            <HolographicAvatar user={user} currentMood={currentMood} />
            <div className="hero-text">
              <h1 className="username">Arnav._.singh__</h1>
              <div className="mood-indicator">
                <span className="mood-emoji">😊</span>
                <span className="mood-text">Feeling Great</span>
              </div>
              <p className="motivational-tagline">
                "Keep pushing, Arnav — you're leveling up your mind! 🚀"
              </p>
            </div>
          </div>
        </section>

        {/* Gamified Stats */}
        <section className="stats-section">
          <div className="stats-grid">
            <div className="stat-card streak-card">
              <div className="stat-icon">🔥</div>
              <div className="stat-content">
                <div className="stat-value">12</div>
                <div className="stat-label">Day Streak</div>
                <ProgressBar current={12} total={21} label="Next milestone" reward="Mystery Pack 🎁" />
              </div>
            </div>
            
            <div className="stat-card coins-card">
              <div className="stat-icon">🪙</div>
              <div className="stat-content">
                <div className="stat-value">2,450</div>
                <div className="stat-label">Mood Coins</div>
                <button className="earn-coins-btn">Tap to earn more →</button>
              </div>
            </div>
            
            <div className="stat-card plan-card">
              <div className="stat-icon">💎</div>
              <div className="stat-content">
                <div className={`plan-badge ${user.is_premium ? 'premium' : 'basic'}`}>
                  {user.is_premium ? '🌟 Premium' : '💎 Basic'}
                </div>
                <div className="plan-label">Current Plan</div>
                {!user.is_premium && (
                  <button className="upgrade-btn">Upgrade to Premium</button>
                )}
              </div>
            </div>
          </div>
        </section>

        {/* Quick Overview */}
        <section className="overview-section">
          <div className="overview-grid">
            <div className="overview-card mood-graph-card">
              <h3>Mood Trend</h3>
              <MiniMoodGraph data={moodData} />
            </div>
            
            <div className="overview-card checkin-card">
              <h3>Daily Check-in</h3>
              <div className="checkin-status">
                <span className="status-emoji">✅</span>
                <span className="status-text">Completed</span>
              </div>
              <p>You're on track! 🎯</p>
            </div>
            
            <div className="overview-card wellness-card">
              <h3>Mental XP</h3>
              <div className="xp-display">
                <div className="xp-level">Level 8</div>
                <div className="xp-progress">
                  <div className="xp-bar" style={{ width: '75%' }}></div>
                </div>
                <div className="xp-text">75/100 to next level</div>
              </div>
            </div>
          </div>
        </section>

        {/* Tools & Features */}
        <section className="tools-section">
          <div className="tools-category">
            <h3 className="category-title">🧘 Wellness Tools</h3>
            <div className="tools-grid">
              {tools.wellness.map(tool => (
                <div 
                  key={tool.id}
                  className={`tool-card ${!tool.free ? 'premium-tool' : ''}`}
                  onClick={() => handleToolClick(tool)}
                >
                  <div className="tool-icon">{tool.icon}</div>
                  <div className="tool-name">{tool.name}</div>
                  <div className={`tool-badge ${tool.free ? 'free' : 'premium'}`}>
                    {tool.free ? 'Free' : 'Premium'}
                  </div>
                </div>
              ))}
            </div>
          </div>

          <div className="tools-category">
            <h3 className="category-title">📈 Self-Growth</h3>
            <div className="tools-grid">
              {tools.growth.map(tool => (
                <div 
                  key={tool.id}
                  className={`tool-card ${!tool.free ? 'premium-tool' : ''}`}
                  onClick={() => handleToolClick(tool)}
                >
                  <div className="tool-icon">{tool.icon}</div>
                  <div className="tool-name">{tool.name}</div>
                  <div className={`tool-badge ${tool.free ? 'free' : 'premium'}`}>
                    {tool.free ? 'Free' : 'Premium'}
                  </div>
                </div>
              ))}
            </div>
          </div>

          <div className="tools-category">
            <h3 className="category-title">🎨 Customization</h3>
            <div className="tools-grid">
              {tools.customization.map(tool => (
                <div 
                  key={tool.id}
                  className="tool-card"
                  onClick={() => handleToolClick(tool)}
                >
                  <div className="tool-icon">{tool.icon}</div>
                  <div className="tool-name">{tool.name}</div>
                  <div className="tool-badge free">Free</div>
                </div>
              ))}
            </div>
          </div>
        </section>

        {/* Rewards & Progress */}
        <section className="rewards-section">
          <h3>🎁 Rewards & Progress</h3>
          <div className="rewards-content">
            <ProgressBar 
              current={5} 
              total={7} 
              label="7-Day Streak Challenge" 
              reward="Avatar Pack 🎁" 
            />
            <div className="achievements-preview">
              <h4>Your Achievements</h4>
              <AchievementBadges achievements={achievements} />
            </div>
          </div>
        </section>

        {/* Utility Section */}
        <section className="utility-section">
          <div className="utility-buttons">
            <button className="utility-btn settings-btn" onClick={onShowSettings}>
              <span className="btn-icon">⚙️</span>
              Settings
            </button>
            
            {!user.is_premium && (
              <button className="utility-btn upgrade-btn premium">
                <span className="btn-icon">💎</span>
                Upgrade to Premium
              </button>
            )}
            
            <button className="utility-btn logout-btn" onClick={onLogout}>
              <span className="btn-icon">🚪</span>
              Logout
            </button>
          </div>
        </section>
      </div>
    </div>
  );
}

export default Profile;
